1	import * as vscode from "vscode";
2	import { dirname } from "path";
3	import { fileURLToPath } from "url";
4	import { openCheckpointDiff } from "./diffUtils.js";
5	import { CheckpointTreeProvider } from "./CheckpointTreeProvider.js";
6	
7	const __dirname = dirname(fileURLToPath(import.meta.url));
8	
9	export class SessionDetailPanel {
10	  private static panels = new Map<string, SessionDetailPanel>();
11	
12	  static createOrShow(
13	    context: vscode.ExtensionContext,
14	    sessionId: string,
15	    title: string,
16	    port: number,
17	    checkpointProvider: CheckpointTreeProvider,
18	    highlight?: string,
19	  ): void {
20	    const existing = SessionDetailPanel.panels.get(sessionId);
21	    if (existing) {
22	      existing.panel.reveal();
23	      checkpointProvider.setSession(sessionId, port).catch(console.error);
24	      return;
25	    }
26	    const shortTitle = title.length > 40 ? title.slice(0, 39) + "…" : title;
27	    new SessionDetailPanel(context, sessionId, shortTitle, port, checkpointProvider, highlight);
28	  }
29	
30	  private readonly panel: vscode.WebviewPanel;
31	
32	  private constructor(
33	    context: vscode.ExtensionContext,
34	    sessionId: string,
35	    title: string,
36	    port: number,
37	    checkpointProvider: CheckpointTreeProvider,
38	    highlight?: string,
39	  ) {
40	    this.panel = vscode.window.createWebviewPanel(
41	      `gossamer.session.${sessionId}`,
42	      title,
43	      vscode.ViewColumn.One,
