71	      const textBlocks  = le.contents.filter((c) => c.contentType === "text");
72	
73	      if (toolResults.length > 0) {
74	        for (const tr of toolResults) {
75	          const failed = tr.isError === true;
76	          result.push({ id: id--, timestamp: ts, event: failed ? "PostToolUseFailure" : "PostToolUse", sessionId: sid, blocked: false, data: { tool_use_id: tr.toolUseId, tool_response: !failed ? (tr.toolResultContent ?? "") : undefined, error: failed ? (tr.toolResultContent ?? "") : undefined }, summary: null, keywords: [], _sourceLogEventId: le.id, _sourceUuid: le.uuid ?? undefined });
77	        }
78	      } else if (textBlocks.length > 0) {
79	        const prompt = textBlocks.map((b) => b.text ?? "").join("\n\n");
80	        result.push({ id: id--, timestamp: ts, event: "UserPromptSubmit", sessionId: sid, blocked: false, data: { prompt }, summary: null, keywords: [], _sourceLogEventId: le.id, _sourceUuid: le.uuid ?? undefined });
81	      }
82	
83	    } else if (le.type === "assistant") {
84	      const toolUses            = le.contents.filter((c) => c.contentType === "tool_use");
85	      const textBlocks          = le.contents.filter((c) => c.contentType === "text");
86	      const thinkingBlocks      = le.contents.filter((c) => c.contentType === "thinking");
87	      const redactedThinkingBlocks = le.contents.filter((c) => c.contentType === "redacted_thinking");
88	
89	      if (!currentTurnLogEventIds.includes(le.id)) currentTurnLogEventIds.push(le.id);
90	
91	      if (textBlocks.length > 0) {
92	        const newText = textBlocks.map((b) => b.text ?? "").filter(Boolean).join("\n\n");
93	        if (lastAssistantText !== null && lastToolsLogEventId !== null) {
94	          lastAssistantThinking = lastAssistantThinking ? lastAssistantThinking + "\n\n" + lastAssistantText : lastAssistantText;
95	        }
96	        lastAssistantText = newText;
97	        lastAssistantLogEventId = le.id;
98	      }
99	      if (thinkingBlocks.length > 0) {
100	        const thinking = thinkingBlocks.map((b) => b.thinking ?? "").filter(Boolean).join("\n\n");
101	        lastAssistantThinking = lastAssistantThinking ? lastAssistantThinking + "\n\n" + thinking : thinking;
102	        lastThinkingLogEventId = le.id;
103	        lastThinkingUuid = le.uuid ?? null;
104	        if (lastAssistantLogEventId === null) lastAssistantLogEventId = le.id;
105	      }
106	      if (redactedThinkingBlocks.length > 0) {
107	        hasRedactedThinking = true;
108	        if (lastAssistantLogEventId === null) lastAssistantLogEventId = le.id;
109	      }
110	      for (const tu of toolUses) {
111	        lastToolsLogEventId = le.id;
112	        lastToolsUuid = le.uuid ?? null;
113	        result.push({ id: id--, timestamp: ts, event: "PreToolUse", sessionId: sid, blocked: false, data: { tool_name: tu.toolName ?? "?", tool_use_id: tu.toolUseId, tool_input: tu.toolInput }, summary: null, keywords: [], _sourceLogEventId: le.id, _sourceUuid: le.uuid ?? undefined });
114	      }
115	
116	    } else if (le.type === "system" && le.systemData?.subtype === "stop_hook_summary") {
117	      const primaryId = lastAssistantLogEventId ?? le.id;
118	      const extraIds  = currentTurnLogEventIds.filter((x) => x !== primaryId);
119	      result.push({ id: id--, timestamp: ts, event: "Stop", sessionId: sid, blocked: le.systemData.preventedContinuation ?? false, data: { last_assistant_message: lastAssistantText ?? "", thinking: lastAssistantThinking ?? "", reason: le.systemData.stopReason ?? "", thinkingLogEventId: lastThinkingLogEventId ?? undefined, thinkingUuid: lastThinkingUuid ?? undefined, toolsLogEventId: lastToolsLogEventId ?? undefined, toolsUuid: lastToolsUuid ?? undefined, hasRedactedThinking }, summary: null, keywords: [], _sourceLogEventId: primaryId, _extraSourceLogEventIds: extraIds.length > 0 ? extraIds : undefined });
120	      lastAssistantText = null; lastAssistantThinking = null; lastAssistantLogEventId = null;
121	      lastThinkingLogEventId = null; lastThinkingUuid = null; lastToolsLogEventId = null; lastToolsUuid = null;
122	      hasRedactedThinking = false; currentTurnLogEventIds.length = 0;
123	    }
124	  }
125	
126	  if (lastAssistantText !== null && filtered.length > 0) {
127	    const last = filtered[filtered.length - 1];
128	    const primaryId = lastAssistantLogEventId ?? last.id;
129	    const extraIds  = currentTurnLogEventIds.filter((x) => x !== primaryId);
130	    result.push({ id: id--, timestamp: last.timestamp ?? "", event: "Stop", sessionId: last.sessionId ?? "", blocked: false, data: { last_assistant_message: lastAssistantText, thinking: lastAssistantThinking ?? "", reason: "" }, summary: null, keywords: [], _sourceLogEventId: primaryId, _extraSourceLogEventIds: extraIds.length > 0 ? extraIds : undefined });
131	  }
132	
133	  return result;
134	}
135	
136	// ── groupEvents ───────────────────────────────────────────────────────────────
137	
138	export function groupEvents(events: Event[]): DisplayItem[] {
139	  const postMap = new Map<string, Event>();
140	  for (const event of events) {
141	    if (event.event === "PostToolUse" || event.event === "PostToolUseFailure") {
142	      const d = event.data as Record<string, unknown>;
143	      const id = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
144	      if (id) postMap.set(id, event);
145	    }
146	  }
147	
148	  type RawItem = { kind: "event"; event: Event } | { kind: "toolUse"; pre: Event; post?: Event; failed: boolean };
149	  const raw: RawItem[] = [];
150	  const consumed = new Set<number>();
151	
152	  for (const event of events) {
153	    if ((event.event === "PostToolUse" || event.event === "PostToolUseFailure") && consumed.has(event.id)) continue;
154	    if (event.event === "PreToolUse") {
155	      const d = event.data as Record<string, unknown>;
156	      const toolUseId = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
157	      const post = toolUseId ? postMap.get(toolUseId) : undefined;
158	      if (post) consumed.add(post.id);
159	      raw.push({ kind: "toolUse", pre: event, post, failed: post?.event === "PostToolUseFailure" });
160	      continue;
161	    }
162	    raw.push({ kind: "event", event });
163	  }
164	
165	  const isGroupable = (item: RawItem) =>
166	    item.kind === "toolUse" || (item.kind === "event" && item.event.event === "Notification");
167	
168	  const result: DisplayItem[] = [];
169	  let i = 0;
170	  while (i < raw.length) {
171	    if (isGroupable(raw[i])) {
172	      const group: ToolUseData[] = [];
173	      while (i < raw.length && isGroupable(raw[i])) {
174	        const item = raw[i];
175	        if (item.kind === "toolUse") group.push({ pre: item.pre, post: item.post, failed: item.failed });
176	        i++;
177	      }
178	      if (group.length > 0) result.push({ kind: "toolGroup", tools: group });
179	    } else {
180	      result.push({ kind: "event", event: (raw[i] as { kind: "event"; event: Event }).event });
181	      i++;
182	    }
183	  }
184	  return result;
185	}
186	
187	// ── groupClaudeTurns ──────────────────────────────────────────────────────────
188	
189	export function groupClaudeTurns(items: DisplayItem[]): RenderItem[] {
190	  const result: RenderItem[] = [];
191	  let i = 0;
192	  while (i < items.length) {
193	    const item = items[i];
194	    if (item.kind === "toolGroup") {
195	      const toolGroups: ToolUseData[][] = [];
196	      while (i < items.length && items[i].kind === "toolGroup") {
197	        toolGroups.push((items[i] as { kind: "toolGroup"; tools: ToolUseData[] }).tools);
198	        i++;
199	      }
200	      let stop: Event | null = null;
201	      if (i < items.length && items[i].kind === "event" && (items[i] as { kind: "event"; event: Event }).event.event === "Stop") {
202	        stop = (items[i] as { kind: "event"; event: Event }).event;
203	        i++;
204	      }
205	      result.push({ kind: "claudeTurn", toolGroups, stop });
206	    } else if (item.kind === "event" && item.event.event === "Stop") {
207	      result.push({ kind: "claudeTurn", toolGroups: [], stop: item.event });
208	      i++;
209	    } else {
210	      result.push({ kind: "event", event: (item as { kind: "event"; event: Event }).event });
211	      i++;
212	    }
213	  }
214	  return result;
215	}
216	
217	// ── ClaudeTurnCard ────────────────────────────────────────────────────────────
218	
219	function highlightText(text: string, terms: string[]): React.ReactNode {
220	  if (!terms.length) return text;
221	  const pattern = terms.map((t) => t.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")).join("|");
222	  const parts = text.split(new RegExp(`(${pattern})`, "gi"));
223	  return <>{parts.map((p, i) => i % 2 === 1 ? <mark key={i} style={{ background: "rgba(255,200,0,0.45)", borderRadius: 2, padding: "0 1px" }}>{p}</mark> : p)}</>;
224	}
225	
226	function ClaudeTurnCard({ toolGroups, stop, matchTerms }: { toolGroups: ToolUseData[][]; stop: Event | null; matchTerms?: string[] }) {
227	  const d      = stop ? (stop.data ?? {}) as Record<string, unknown> : {};
228	  const msg    = str(d.last_assistant_message);
229	  const thinking = str(d.thinking);
230	  const reason = str(d.reason);
231	  const hasRedactedThinking = d.hasRedactedThinking === true;
232	  const totalTools = toolGroups.reduce((n, g) => n + g.length, 0);
233	  const [toolsExpanded, setToolsExpanded] = useState(false);
234	  const [thinkingExpanded, setThinkingExpanded] = useState(false);
235	
236	  return (
237	    <Box style={{
238	      display: "flex",
239	      gap: 10,
240	      padding: "5px 12px",
241	      paddingLeft: 10,
242	      borderLeft: "2px solid var(--mantine-color-orange-5)",
243	      borderBottom: "1px solid var(--vscode-panel-border)",
244	      alignItems: "flex-start",
245	    }}>
246	      <Text
247	        size="xs"
248	        fw={600}
249	        style={{ width: 52, flexShrink: 0, paddingTop: 2, color: "var(--mantine-color-orange-5)", whiteSpace: "nowrap" }}
250	      >
251	        Claude
252	      </Text>
253	      <Box style={{ flex: 1, minWidth: 0 }}>
254	        {reason && <Badge color="orange" size="xs" variant="light" mb={4}>{reason}</Badge>}
255	        {!thinking && hasRedactedThinking && (
256	          <Text size="xs" c="dimmed" fs="italic" mb={4}>thinking (redacted)</Text>
257	        )}
258	        {thinking && (
259	          <Box mb={4}>
260	            <Group gap={6} style={{ cursor: "pointer" }} onClick={() => setThinkingExpanded((v) => !v)}>
261	              <Text size="xs" c="dimmed" fs="italic">thinking {thinkingExpanded ? "▲" : "▼"}</Text>
262	            </Group>
263	            <Collapse in={thinkingExpanded}>
264	              <Box mt={4} style={{ backgroundColor: "var(--vscode-textCodeBlock-background)", border: "1px solid var(--vscode-panel-border)", borderRadius: 4, padding: "8px 12px", fontFamily: "var(--vscode-editor-font-family, monospace)", fontSize: 12, lineHeight: 1.6, whiteSpace: "pre-wrap", wordBreak: "break-word", color: "var(--vscode-descriptionForeground)" }}>
265	                {highlightText(thinking, matchTerms ?? [])}
266	              </Box>
267	            </Collapse>
268	          </Box>
269	        )}
270	        {stop && msg && <Box mb={toolGroups.length > 0 ? 6 : 0}>{matchTerms?.length ? (
271	          <Text size="sm" style={{ whiteSpace: "pre-wrap", lineHeight: "18px" }}>
272	            {highlightText(msg, matchTerms)}
273	          </Text>
274	        ) : <MarkdownView text={msg} />}</Box>}
275	        {toolGroups.length > 0 && (
276	          <Box>
277	            <Group gap={6} style={{ cursor: "pointer" }} onClick={() => setToolsExpanded((v) => !v)}>
278	              <Text size="xs" c="dimmed">{totalTools} tool {totalTools === 1 ? "use" : "uses"}</Text>
279	              <Text size="xs" c="dimmed">{toolsExpanded ? "▲" : "▼"}</Text>
280	            </Group>
281	            <Collapse in={toolsExpanded}>
282	              <Box mt={4} style={{ display: "flex", flexDirection: "column", gap: 4 }}>
283	                {toolGroups.map((tools, i) => <ToolGroupItem key={i} tools={tools} matchTerms={matchTerms} />)}
284	              </Box>
285	            </Collapse>
286	          </Box>
287	        )}
288	      </Box>
289	      <Box style={{ flexShrink: 0, paddingTop: 2 }}>
290	        {stop && <TimeAgo iso={stop.timestamp} />}
291	      </Box>
292	    </Box>
293	  );
294	}
295	
296	// ── SessionDetail screen ──────────────────────────────────────────────────────
297	
298	interface Props {
299	  sessionId: string;
300	  title: string;
301	  onBack?: () => void;
302	}
303	
304	const highlightQuery = (window as unknown as Record<string, unknown>).__GOSSAMER_HIGHLIGHT__;
305	const HIGHLIGHT_TERMS: string[] = typeof highlightQuery === "string" && highlightQuery.trim()
306	  ? highlightQuery.trim().split(/\s+/).filter(Boolean)
307	  : [];
308	
309	export function SessionDetail({ sessionId, title, onBack }: Props) {
310	  const [session, setSession]         = useState<Session | null>(null);
311	  const [renderItems, setRenderItems] = useState<RenderItem[]>([]);
312	  const [loading, setLoading]         = useState(true);
313	  const [error, setError]             = useState<string | null>(null);
314	  const viewport = useRef<HTMLDivElement>(null);
315	  const initialLoadDone = useRef(false);
316	  const matchTerms = HIGHLIGHT_TERMS;
317	
318	  async function load() {
319	    try {
320	      const [sess, logEvents] = await Promise.all([
321	        fetchSession(sessionId),
322	        fetchLogEvents(sessionId),
323	      ]);
324	      setSession(sess);
325	      const events  = logEventsToEvents(logEvents);
326	      const display = groupEvents(events);
327	      setRenderItems(groupClaudeTurns(display));
328	      setError(null);
329	    } catch (err) {
330	      setError(String(err));
331	    }
332	  }
333	
334	  useEffect(() => {
335	    initialLoadDone.current = false;
336	    load().finally(() => {
337	      setLoading(false);
338	      initialLoadDone.current = true;
339	      setTimeout(() => {
340	        if (matchTerms.length > 0) {
341	          const mark = viewport.current?.querySelector("mark");
342	          mark?.scrollIntoView({ behavior: "smooth", block: "center" });
343	        } else {
344	          const el = viewport.current;
345	          if (el) el.scrollTop = el.scrollHeight;
346	        }
347	      }, 0);
348	    });
349	  }, [sessionId]);
350	
351	  useEffect(() => {
352	    return subscribeToUpdates(() => { load().catch(() => undefined); });
353	  }, [sessionId]);
354	
355	  // Auto-scroll only when new content arrives on a live session and user is already near bottom
356	  useEffect(() => {
357	    if (!initialLoadDone.current) return;
358	    if (!session?.isLive) return;
359	    const el = viewport.current;
360	    if (!el) return;
361	    if (el.scrollHeight - el.scrollTop - el.clientHeight < 80) {
362	      el.scrollTo({ top: el.scrollHeight, behavior: "smooth" });
363	    }
364	  }, [renderItems]);
365	
366	  if (loading) return <Center style={{ flex: 1 }}><Loader size="md" color="indigo" /></Center>;
367	
368	  if (error) {
369	    return (
370	      <Center style={{ flex: 1, padding: 24 }}>
371	        <Text size="sm" c="red">{error}</Text>
372	      </Center>
373	    );
374	  }
375	
376	  return (
377	    <Box style={{ flex: 1, overflow: "hidden", display: "flex", flexDirection: "column" }}>
378	      {/* Header */}
379	      <Box style={{ borderBottom: "1px solid var(--vscode-panel-border)", flexShrink: 0 }}>
380	        <Group px={12} py={6} gap={8}>
381	          {onBack && (
382	            <ActionIcon variant="subtle" size="sm" onClick={onBack} title="Back to sessions">←</ActionIcon>
383	          )}
384	          <Text size="sm" fw={600} style={{ flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
385	            {session?.intent ?? session?.summary ?? title}
386	          </Text>
387	          {session?.branch && <Text size="xs" ff="monospace" c="teal">{session.branch}</Text>}
388	          {session?.isLive && <Badge size="xs" color="orange" variant="light">live</Badge>}
389	          <ActionIcon
390	            size="sm"
391	            variant="subtle"
392	            title="Resume session in terminal"
393	            onClick={() => postToExtension({ type: "resume_session", sessionId, cwd: session?.cwd ?? "" })}
394	          >▶</ActionIcon>
395	        </Group>
396	        {session && (
397	          <Group px={12} pb={5} gap={16}>
398	            {session.cwd && (
399	              <Text size="xs" c="dimmed" ff="monospace" style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", maxWidth: 320 }}>
400	                {session.cwd}
401	              </Text>
402	            )}
403	            {session.gitUserName && <Text size="xs" c="dimmed">{session.gitUserName}</Text>}
404	            <Text size="xs" c="dimmed">started <TimeAgo iso={session.startedAt} /></Text>
405	            <Text size="xs" c="dimmed">updated <TimeAgo iso={session.updatedAt} /></Text>
406	          </Group>
407	        )}
408	      </Box>
409	
410	      {/* Body: events */}
411	      <ScrollArea style={{ flex: 1 }} viewportRef={viewport}>
412	        <Box pb={32}>
413	          {renderItems.map((item, i) => {
414	            if (item.kind === "claudeTurn") {
415	              return <ClaudeTurnCard key={i} toolGroups={item.toolGroups} stop={item.stop} matchTerms={matchTerms} />;
416	            }
417	            return <EventItem key={i} event={item.event} matchTerms={matchTerms} />;
418	          })}
419	        </Box>
420	      </ScrollArea>
421	    </Box>
422	  );
423	}
